import{_ as t,a as e,b as i,c as l,d as r,e as d,f as o,g as h}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as p,o as s,c as n,a2 as c}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"聯盟分散式索引使用說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/federated-distributed-index.md","filePath":"zh-TW/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),b={name:"zh-TW/Other/federated-distributed-index.md"};function u(m,a,q,x,_,f){return s(),n("div",null,[...a[0]||(a[0]=[c('<h1 id="聯盟分散式索引使用說明" tabindex="-1">聯盟分散式索引使用說明 <a class="header-anchor" href="#聯盟分散式索引使用說明" aria-label="Permalink to &quot;聯盟分散式索引使用說明&quot;">​</a></h1><p>聯盟分散式索引用來讓多個 ImgBed 站台互相共享檔案列表。</p><p>簡單來說：</p><ul><li>你可以把自己的某些資料夾分享給別人。</li><li>你也可以加入別人的節點，把對方分享的檔案列表同步到自己的後台查看。</li><li>聯盟檔案主要用來瀏覽、搜尋和開啟連結，不會在本機重新上傳一份檔案。</li></ul><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; 聯盟分散式索引</span></span></code></pre></div><p><img src="'+t+`" alt="聯盟分散式索引本機節點" loading="lazy"></p><p>頁面分成三個分頁：</p><table tabindex="0"><thead><tr><th>分頁</th><th>用途</th></tr></thead><tbody><tr><td>本機節點</td><td>設定自己的聯盟開關、對外網域、共享資料夾，並更新索引</td></tr><tr><td>我加入的節點</td><td>管理自己加入的其他 ImgBed 節點</td></tr><tr><td>加入我的節點</td><td>管理別人申請加入你的節點</td></tr></tbody></table><h2 id="第一次使用怎麼設定" tabindex="-1">第一次使用怎麼設定 <a class="header-anchor" href="#第一次使用怎麼設定" aria-label="Permalink to &quot;第一次使用怎麼設定&quot;">​</a></h2><ol><li>打開「本機節點」。</li><li>開啟「啟用」。</li><li>在「同步資料夾」裡選擇要分享出去的資料夾。</li><li>點「更新出站索引」。</li><li>如果系統提示偵測到網域變更，確認目前網域沒問題後繼續。</li></ol><p>同步資料夾可以選多個。</p><p>如果同步資料夾清空，代表分享全部資料夾。</p><h2 id="本機節點怎麼用" tabindex="-1">本機節點怎麼用 <a class="header-anchor" href="#本機節點怎麼用" aria-label="Permalink to &quot;本機節點怎麼用&quot;">​</a></h2><h3 id="對外網域" tabindex="-1">對外網域 <a class="header-anchor" href="#對外網域" aria-label="Permalink to &quot;對外網域&quot;">​</a></h3><p>對外網域是別人訪問你這個節點時使用的站台網址。</p><p>這個網址由系統自動辨識，不需要手動填。第一次更新索引時，系統會讓你確認目前訪問網址是不是正式網域。</p><p>如果之後換網域，再點更新索引時也會再次提示確認。</p><h3 id="同步資料夾" tabindex="-1">同步資料夾 <a class="header-anchor" href="#同步資料夾" aria-label="Permalink to &quot;同步資料夾&quot;">​</a></h3><p>同步資料夾決定哪些檔案會分享給聯盟節點。</p><p>例如你只選：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>別人同步你的節點時，就只能看到這兩個目錄裡的檔案。</p><h3 id="更新出站索引" tabindex="-1">更新出站索引 <a class="header-anchor" href="#更新出站索引" aria-label="Permalink to &quot;更新出站索引&quot;">​</a></h3><p>這個按鈕用來更新「我分享給別人看的檔案列表」。</p><p>適合在這些時候點：</p><ul><li>第一次啟用聯盟。</li><li>新上傳了一批想分享的檔案。</li><li>修改了同步資料夾。</li><li>更換對外網域後需要確認新網域。</li></ul><h2 id="我加入的節點怎麼用" tabindex="-1">我加入的節點怎麼用 <a class="header-anchor" href="#我加入的節點怎麼用" aria-label="Permalink to &quot;我加入的節點怎麼用&quot;">​</a></h2><p>「我加入的節點」是你訂閱別人節點的地方。</p><p><img src="`+e+'" alt="我加入的節點" loading="lazy"></p><h3 id="申請加入別人" tabindex="-1">申請加入別人 <a class="header-anchor" href="#申請加入別人" aria-label="Permalink to &quot;申請加入別人&quot;">​</a></h3><ol><li>跟對方要一條邀請連結。</li><li>貼到輸入框。</li><li>點「申請加入」。</li><li>等對方在自己的後台同意。</li></ol><p>對方同意後，節點狀態會變成「已同意」。</p><h3 id="更新入站索引" tabindex="-1">更新入站索引 <a class="header-anchor" href="#更新入站索引" aria-label="Permalink to &quot;更新入站索引&quot;">​</a></h3><p>更新入站索引用來把你已加入節點的檔案列表同步到本機。</p><p>適合在這些時候點：</p><ul><li>對方剛同意你的申請後。</li><li>對方告訴你他更新了共享內容。</li><li>你想刷新全部已加入節點的聯盟檔案列表。</li></ul><p>如果只想更新某一個節點，可以在該節點卡片上點「更新索引」。</p><p><img src="'+i+'" alt="更新索引" loading="lazy"></p><h3 id="取消訂閱" tabindex="-1">取消訂閱 <a class="header-anchor" href="#取消訂閱" aria-label="Permalink to &quot;取消訂閱&quot;">​</a></h3><p>如果不想繼續同步某個節點，可以點「取消訂閱」。</p><p>取消後，這個節點的聯盟索引也會從本機清掉。</p><h2 id="加入我的節點怎麼用" tabindex="-1">加入我的節點怎麼用 <a class="header-anchor" href="#加入我的節點怎麼用" aria-label="Permalink to &quot;加入我的節點怎麼用&quot;">​</a></h2><p>「加入我的節點」是別人申請加入你的地方。</p><p><img src="'+l+'" alt="加入我的節點" loading="lazy"></p><h3 id="產生邀請連結" tabindex="-1">產生邀請連結 <a class="header-anchor" href="#產生邀請連結" aria-label="Permalink to &quot;產生邀請連結&quot;">​</a></h3><ol><li>先確認本機節點已啟用。</li><li>先點過「更新出站索引」，讓系統確認對外網域。</li><li>打開「加入我的節點」。</li><li>點「重設邀請連結」。</li><li>複製邀請連結傳給對方。</li></ol><p>如果邀請連結是空的，通常是還沒確認對外網域。回到「本機節點」點一次「更新出站索引」即可。</p><h3 id="處理加入申請" tabindex="-1">處理加入申請 <a class="header-anchor" href="#處理加入申請" aria-label="Permalink to &quot;處理加入申請&quot;">​</a></h3><p>別人送出申請後，會出現在「加入我的節點」列表。</p><table tabindex="0"><thead><tr><th>操作</th><th>作用</th></tr></thead><tbody><tr><td>同意</td><td>允許對方同步你分享的檔案列表</td></tr><tr><td>拒絕</td><td>不允許對方加入</td></tr><tr><td>刪除</td><td>刪除已結束的紀錄</td></tr><tr><td>檢查狀態</td><td>檢查對方是否仍保留這段關係</td></tr></tbody></table><p>同意後，對方還需要在自己那邊點「更新入站索引」，才會看到你分享的檔案列表。</p><p><img src="'+r+'" alt="邀請節點同意" loading="lazy"></p><h2 id="留言功能" tabindex="-1">留言功能 <a class="header-anchor" href="#留言功能" aria-label="Permalink to &quot;留言功能&quot;">​</a></h2><p>關係已同意後，可以在節點卡片裡點「留言」。</p><p>留言只用於聯盟關係溝通，不會影響檔案、標籤、目錄和存取權限。</p><p><img src="'+d+'" alt="留言功能" loading="lazy"></p><h2 id="在哪裡看聯盟檔案" tabindex="-1">在哪裡看聯盟檔案 <a class="header-anchor" href="#在哪裡看聯盟檔案" aria-label="Permalink to &quot;在哪裡看聯盟檔案&quot;">​</a></h2><p>同步完成後，回到管理後台檔案列表。</p><p>頁面頂部可以在本機檔案和聯盟檔案之間切換。切到聯盟檔案後，就能瀏覽已同步的聯盟內容。</p><p>聯盟檔案主要用於查看、搜尋、預覽和複製連結。它不是本機檔案，所以不能在本機直接移動、刪除、改標籤或備份。</p><p><img src="'+o+'" alt="聯盟管理顯示效果" loading="lazy"></p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="為什麼提示沒有關係紀錄-需要重新申請" tabindex="-1">為什麼提示沒有關係紀錄，需要重新申請？ <a class="header-anchor" href="#為什麼提示沒有關係紀錄-需要重新申請" aria-label="Permalink to &quot;為什麼提示沒有關係紀錄，需要重新申請？&quot;">​</a></h3><p>通常是對方把你刪除並清掉紀錄，導致系統查不到這段關係。這時需要重新申請。</p><p><img src="'+h+'" alt="無關係紀錄重新申請" loading="lazy"></p><h3 id="為什麼加入後看不到檔案" tabindex="-1">為什麼加入後看不到檔案？ <a class="header-anchor" href="#為什麼加入後看不到檔案" aria-label="Permalink to &quot;為什麼加入後看不到檔案？&quot;">​</a></h3><p>先確認：</p><ol><li>對方已同意你的申請。</li><li>對方已點過「更新出站索引」。</li><li>你已點過「更新入站索引」。</li><li>對方的同步資料夾確實包含要分享的目錄。</li></ol><h3 id="提示網域變更怎麼辦" tabindex="-1">提示網域變更怎麼辦？ <a class="header-anchor" href="#提示網域變更怎麼辦" aria-label="Permalink to &quot;提示網域變更怎麼辦？&quot;">​</a></h3><p>如果你現在開後台用的就是正式網域，可以確認繼續。</p><p>如果只是臨時用其他網址進後台，建議取消，改用正式網域重新打開後台再操作。</p><h3 id="同步資料夾清空是什麼意思" tabindex="-1">同步資料夾清空是什麼意思？ <a class="header-anchor" href="#同步資料夾清空是什麼意思" aria-label="Permalink to &quot;同步資料夾清空是什麼意思？&quot;">​</a></h3><p>同步資料夾清空代表分享全部資料夾。</p><p>如果只想分享部分目錄，請手動選擇對應資料夾。</p><h3 id="更新出站和更新入站有什麼差別" tabindex="-1">更新出站和更新入站有什麼差別？ <a class="header-anchor" href="#更新出站和更新入站有什麼差別" aria-label="Permalink to &quot;更新出站和更新入站有什麼差別？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按鈕</th><th>簡單理解</th></tr></thead><tbody><tr><td>更新出站索引</td><td>更新「別人能從我這裡同步到什麼」</td></tr><tr><td>更新入站索引</td><td>更新「我從別人那裡同步到了什麼」</td></tr></tbody></table>',77)])])}const y=p(b,[["render",u]]);export{P as __pageData,y as default};
